using System.Collections;
using UnityEngine;

/// <summary>
/// Tipos de coleccionável do mundo — usado por
/// <see cref="PlayerProgress.PickupCollected"/> para identificar a UI/SFX/
/// estatística correcta sem cada Pickup ter de conhecer esses sistemas
/// directamente.
/// </summary>
public enum PickupType
{
    RunaDeGaia,
    Semente,
    FragmentoVital,
    BrotoDeVida,
    SussurroDaTerra,

    /// <summary>
    /// Eco Perdido — coleccionável escondido nas fases (exploração / puzzles).
    /// Serve de moeda para comprar Sussurros da Terra no Contador de Histórias.
    /// Cada área tem normalmente 15 Ecos Perdidos (preços dos Sussurros: 1-2-3-4-5).
    /// Áreas de Vila e de Boss não têm Ecos Perdidos.
    /// </summary>
    EcoPerdido,

    Chest,
    MissionReward,

    /// <summary>
    /// Melodia Selvagem — faixa musical especial encontrada pelo mundo que
    /// desbloqueia no Jukebox e conta para os 100% do save.
    /// </summary>
    WildMelody,

    /// <summary>
    /// Bolha de Ar — coleccionável subaquático que restaura o oxigênio de
    /// animais terrestres que mergulham. Não conta para descobertas nem
    /// estatísticas de área (Task #26 — separar do BrotoDeVida).
    /// </summary>
    BolhaDeAr,
}

/// <summary>
/// Classe base para todos os coleccionáveis do mundo (Runa de Gaia, Semente,
/// Fragmento Vital, Broto de Vida, Sussurro da Terra, baús, recompensas de
/// missão, ...).
///
/// Responsabilidades comuns (todas tratadas aqui, sem repetição nas
/// subclasses):
/// - Detecção do player via <c>OnTriggerEnter2D</c> + tag "Player" (mesmo
///   padrão de <see cref="SafeHaven"/>).
/// - Anti-duplicação: se <see cref="pickupId"/> já estiver em
///   <c>PlayerProgress.collectedPickupIds</c> (recolhido numa sessão/save
///   anterior), o objecto desactiva-se em <c>Start()</c> e nunca concede a
///   recompensa outra vez.
/// - Efeitos: som (<see cref="collectSfx"/>), VFX (<see cref="collectVfxPrefab"/>)
///   e popup temporário (<see cref="popupText"/> via <see cref="PickupPopupUI"/>).
/// - Autosave opcional após recolher (<see cref="autosaveOnCollect"/>).
/// - Suporte a íman (<see cref="canBeMagnetized"/>) — ver <see cref="PickupMagnet"/>.
///
/// Subclasses só precisam de implementar <see cref="Type"/> (para o evento
/// <c>PlayerProgress.PickupCollected</c>) e <see cref="GrantReward"/> (conceder
/// a recompensa específica — chamar GiveSementes/GiveRunasDeGaia/AddRunaFound/
/// etc.).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public abstract class PickupBase : MonoBehaviour
{
    [Header("Identidade")]
    [Tooltip("ID persistente e único deste coleccionável (ex: 'runa_floresta_03'). Usado por PlayerProgress.collectedPickupIds para impedir recolha duplicada entre sessões/saves. Deixar vazio desactiva a anti-duplicação — não recomendado para coleccionáveis únicos do mundo (Runas, Fragmentos, baús, Sussurros, recompensas de missão). Para Sementes/Brotos 'genéricos' espalhados pelo nível, pode deixar-se vazio.")]
    public string pickupId;

    [Header("Área (contadores por área)")]
    [Tooltip("Área a que este coleccionável pertence, para os contadores 'encontrados nesta área' (AreaProgress / AreaData.totalRunas, totalFragments, totalWhispers, totalChests). Se vazio, é preenchido automaticamente a partir de WorldState.CurrentArea no Start().")]
    public AreaData area;

    [Header("Feedback")]
    [Tooltip("Som tocado (posicionalmente) ao recolher.")]
    public AudioClip collectSfx;

    [Tooltip("Prefab de efeito visual instanciado na posição do coleccionável ao recolher (opcional — partículas, brilho, etc.).")]
    public GameObject collectVfxPrefab;

    [Tooltip("Texto mostrado num popup temporário ao recolher (ex: '+1 Runa de Gaia'). Vazio = sem popup.")]
    public string popupText;

    [Header("Íman")]
    [Tooltip("Se activo, PickupMagnet (no player) pode atrair este coleccionável para perto antes de o recolher.")]
    public bool canBeMagnetized = true;

    [Header("Autosave")]
    [Tooltip("Se activo, chama SaveManager.Instance.SaveAutosave() imediatamente depois de conceder a recompensa. Usar apenas para coleccionáveis 'importantes' (Runas de Gaia, Fragmentos Vitais, baús, recompensas de missão) — Sementes/Brotos não devem gravar a cada recolha, pelo custo de I/O.")]
    public bool autosaveOnCollect = false;

    [Header("Destaque (Luz de Gaia — Tarefa Itens Consumíveis)")]
    [Tooltip("Prefab de destaque (brilho/seta) instanciado como filho enquanto este coleccionável estiver destacado pela Luz de Gaia. Opcional — sem prefab, usa apenas um pulso de cor no SpriteRenderer.")]
    public GameObject highlightVfxPrefab;

    /// <summary>Tipo deste coleccionável — usado em PlayerProgress.PickupCollected (UI/SFX/estatísticas).</summary>
    public abstract PickupType Type { get; }

    private bool _collected;
    private Coroutine _highlightRoutine;

    /// <summary>True depois de <see cref="Collect"/> ter sido chamado com sucesso (recompensa já concedida).</summary>
    public bool Collected => _collected;

    /// <summary>
    /// Destaca este coleccionável durante "duration" segundos (Luz de Gaia —
    /// PlayerConsumableEffects): instancia <see cref="highlightVfxPrefab"/> (se
    /// configurado) como filho e/ou aplica um pulso de "color" ao
    /// SpriteRenderer. Chamar de novo enquanto já destacado renova a duração.
    /// </summary>
    public void SetHighlighted(Color color, float duration)
    {
        if (_collected) return;

        if (_highlightRoutine != null) StopCoroutine(_highlightRoutine);
        _highlightRoutine = StartCoroutine(HighlightRoutine(color, duration));
    }

    private IEnumerator HighlightRoutine(Color color, float duration)
    {
        GameObject vfx = highlightVfxPrefab != null
            ? Instantiate(highlightVfxPrefab, transform.position, Quaternion.identity, transform)
            : null;

        var sprite = GetComponentInChildren<SpriteRenderer>();
        Color original = sprite != null ? sprite.color : Color.white;

        float t = 0f;
        while (t < duration)
        {
            if (sprite != null)
            {
                float pulse = (Mathf.Sin(t * 6f) + 1f) * 0.5f;
                sprite.color = Color.Lerp(original, color, pulse * 0.6f);
            }

            t += Time.deltaTime;
            yield return null;
        }

        if (sprite != null) sprite.color = original;
        if (vfx != null) Destroy(vfx);
        _highlightRoutine = null;
    }

    protected virtual void Awake()
    {
        var col = GetComponent<Collider2D>();
        if (col != null) col.isTrigger = true;
    }

    protected virtual void Start()
    {
        if (area == null && WorldState.Instance != null)
            area = WorldState.Instance.CurrentArea;

        // Já recolhido numa sessão/save anterior (collectedPickupIds) — não
        // voltar a aparecer nem a conceder a recompensa outra vez.
        if (!string.IsNullOrEmpty(pickupId) && PlayerProgress.Instance != null
            && PlayerProgress.Instance.HasCollectedPickup(pickupId))
        {
            _collected = true;
            gameObject.SetActive(false);
        }
    }

    protected virtual void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        Collect();
    }

    /// <summary>
    /// Recolhe este coleccionável: concede a recompensa (uma única vez via
    /// <see cref="GrantReward"/>), marca-o como recolhido (anti-duplicação),
    /// toca efeitos/som, mostra o popup, notifica
    /// <c>PlayerProgress.PickupCollected</c>, faz autosave (se configurado) e
    /// desactiva/destrói o objecto. Pode ser chamado directamente (ex: por
    /// <see cref="PickupMagnet"/> ou por interacção manual de um baú).
    /// </summary>
    public void Collect()
    {
        if (_collected) return;
        if (!string.IsNullOrEmpty(pickupId) && PlayerProgress.Instance != null
            && PlayerProgress.Instance.HasCollectedPickup(pickupId))
            return;

        _collected = true;

        GrantReward();

        if (!string.IsNullOrEmpty(pickupId))
            PlayerProgress.Instance?.MarkPickupCollected(pickupId);

        if (collectVfxPrefab != null)
            Instantiate(collectVfxPrefab, transform.position, Quaternion.identity);

        AudioManager.Instance?.PlaySEAtPoint(collectSfx, transform.position);

        if (!string.IsNullOrEmpty(popupText))
            PickupPopupUI.Instance?.Show(popupText);

        PlayerProgress.Instance?.NotifyPickupCollected(Type, pickupId);

        if (autosaveOnCollect)
            SaveManager.Instance?.SaveAutosave();

        gameObject.SetActive(false);
        Destroy(gameObject);
    }

    /// <summary>Concede a recompensa específica deste tipo de coleccionável (chamado uma única vez, dentro de Collect()).</summary>
    protected abstract void GrantReward();
}

/// <summary>
/// Uma entrada de "item + quantidade" — usada por <see cref="ChestPickup"/> e
/// <see cref="MissionRewardPickup"/> para configurar o conteúdo entregue
/// (PlayerProgress.AddItem).
/// </summary>
[System.Serializable]
public class PickupLootEntry
{
    public ItemData item;

    [Min(1)]
    public int amount = 1;
}
